import re

def detect_tool_injection(message: str) -> bool:
    tool_pattern = r'{"type":\s*"tool_use"\s*,\s*"id"\s*:.*?"name"\s*:.*?}'
    return bool(re.search(tool_pattern, message, re.DOTALL))

