import json

def trace_tool_origins(response):
    injections = []
    for block in response.content:
        if block.type == 'tool_use':
            tool_input = json.dumps(block.input)
            if any(indicator in tool_input for indicator in ['eval(', 'exec(', '__import__']):
                injections.append({
                    'tool': block.name,
                    'suspicious_input': tool_input
                })
    return injections

