AUTHORIZED_TOOLS = {'file_read', 'database_query', 'email_send'}

def validate_tool_calls(response):
    for block in response.content:
        if block.type == 'tool_use' and block.name not in AUTHORIZED_TOOLS:
            raise ValueError(f'Unauthorized tool: {block.name}')
        # Validate tool input schema
        if 'command' in block.input and 'rm' in block.input['command']:
            raise ValueError('Dangerous command detected')
    return response

